def lcs_len_chars(a, b):
    A = normalize_arabic(a)
    B = normalize_arabic(b)
    n, m = len(A), len(B)
    prev = [0]*(m+1)
    for i in range(1, n+1):
        curr = [0]*(m+1)
        ai = A[i-1]
        for j in range(1, m+1):
            if ai == B[j-1]:
                curr[j] = prev[j-1] + 1
            else:
                curr[j] = max(prev[j], curr[j-1])
        prev = curr
    return prev[m]

def lcs_ratio2(a, b):
    return lcs_len_chars(a, b) / max(len(normalize_arabic(a)), len(normalize_arabic(b)), 1)

def token_f1_2(a, b):
    ta = tokenize(a)
    tb = tokenize(b)
    sa, sb = set(ta), set(tb)
    inter = len(sa & sb)
    if inter == 0:
        return 0.0
    prec = inter / max(len(sa), 1)
    rec = inter / max(len(sb), 1)
    return 2*prec*rec/(prec+rec)

def difflib_ratio2(a, b):
    return difflib.SequenceMatcher(None, normalize_arabic(a), normalize_arabic(b)).ratio()

def score_text2(txt):
    return max(lcs_ratio2(full_span, txt), difflib_ratio2(full_span, txt), token_f1_2(full_span, txt))

